@page "/chat"
@using sv_1865f80848c749d8b1d959fdfdfc9c9a.Services
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="channels"
                    ActiveChannelId="activeChannelId"
                    OnChannelSelected="SelectChannel" />

    <div class="main-and-thread @(isThreadOpen ? "thread-open" : "")">
        @if (activeChannel is not null)
        {
            <MessageArea Channel="activeChannel"
                         Messages="messages"
                         ThreadSummaries="threadSummaries"
                         IsLoadingMore="isLoadingMore"
                         OnSendMessage="SendMessage"
                         OnOpenThread="OpenThread"
                         OnReact="AddReaction"
                         OnLoadMore="LoadMoreMessages" />
        }

        @if (isThreadOpen)
        {
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        }
    </div>
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private List<ThreadSummary> threadSummaries = [];
    private Channel? activeChannel;
    private int activeChannelId;

    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    private bool isLoadingMore;
    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        activeChannelId = channelId;
        activeChannel = channels.FirstOrDefault(c => c.Id == channelId);
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];

        messages = await ChatService.GetMessagesAsync(channelId, skip: 0, take: PageSize);
        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);
        // Refresh channel list to clear unread badge
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task SendMessage(string content)
    {
        if (activeChannel is null) return;
        var newMessage = await ChatService.SendMessageAsync(activeChannel.Id, content, replyToId: null);
        messages.Add(newMessage);
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        isThreadOpen = true;
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (activeChannel is null || threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(activeChannel.Id, content, replyToId: threadRootMessage.Id);
        threadReplies.Add(reply);
        BuildThreadSummaries();
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
        // Refresh messages to reflect the new reaction
        if (activeChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(activeChannel.Id, skip: 0, take: messages.Count);
        }
    }

    private async Task LoadMoreMessages()
    {
        if (activeChannel is null || isLoadingMore) return;
        isLoadingMore = true;

        var older = await ChatService.GetMessagesAsync(activeChannel.Id, skip: messages.Count, take: PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            BuildThreadSummaries();
        }

        isLoadingMore = false;
    }

    private void BuildThreadSummaries()
    {
        threadSummaries = messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .Select(g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)))
            .ToList();
    }
}

